const content =
  ($json && Array.isArray($json.content) && $json.content) ||
  (Array.isArray($json) && $json[0] && Array.isArray($json[0].content) && $json[0].content) ||
  [];

const vendedores = {}; // estrutura: { [codigoVendedor]: { OR:Set, PD:Set, ORparaPD:Map } }

for (const pedido of content) {
  const numero = pedido?.numeroDocumento;
  const especie = pedido?.especieDocumento;
  const vendedor = pedido?.codigoVendedor || "SEM_VENDEDOR";

  if (!numero || !especie) continue;

  // garante a estrutura para o vendedor
  if (!vendedores[vendedor]) {
    vendedores[vendedor] = {
      OR: new Set(),
      PD: new Set(),
      ORparaPD: new Map()
    };
  }

  // adiciona OR ou PD
  if (especie === "OR") vendedores[vendedor].OR.add(numero);
  if (especie === "PD") vendedores[vendedor].PD.add(numero);

  // verifica conversão OR → PD nos itens
  if (pedido.itens) {
    for (const item of pedido.itens) {
      if (item.especieFaturamento === "PD" && item.numeroFaturamento) {
        vendedores[vendedor].ORparaPD.set(numero, item.numeroFaturamento);
      }
    }
  }
}

// monta resultado final por vendedor
const resultadoPorVendedor = Object.entries(vendedores).map(([vendedor, dados]) => {
  const pedidosOR = Array.from(dados.OR);
  const pedidosPD = Array.from(dados.PD);
  const OR_viraram_PD = Array.from(dados.ORparaPD.entries()).map(([or, pd]) => ({
    numeroDocumento: or,
    numeroFaturamento: pd,
    especieFaturamento: "PD"
  }));

  return {
    codigoVendedor: vendedor,
    pedidosOR,
    pedidosPD,
    OR_viraram_PD,
    totais: {
      OR: pedidosOR.length,
      PD: pedidosPD.length,
      OR_convertidos: OR_viraram_PD.length
    }
  };
});

return [{ json: { vendedores: resultadoPorVendedor } }];

// Código para n8n - Code Node
// Análise de Pedidos OR e PD

const content = $input.all().flatMap(item => item.json.content || []);

// Contadores
const OR_naoFaturados = [];
const PD_total = [];
const PD_faturados = [];
const OR_convertidos_para_PD = [];

for (const pedido of content) {
  const especie = pedido.especieDocumento;
  const jaFaturado = pedido.jaFaturado;
  const numero = pedido.numeroDocumento;
  const vendedor = pedido.codigoVendedor;
  const cliente = pedido.cliente?.nome || pedido.nomeConsumidorOuCliente || 'N/A';
  const valor = pedido.valorContabil || 0;

  // 1. OR com jaFaturado = false
  if (especie === "OR" && jaFaturado === false) {
    OR_naoFaturados.push({ numero, vendedor, cliente, valor });
  }

  // 2. Pedidos PD
  if (especie === "PD") {
    PD_total.push({ numero, vendedor, cliente, valor, jaFaturado });

    // 3. PD já faturados
    if (jaFaturado === true) {
      PD_faturados.push({ numero, vendedor, cliente, valor });
    }
  }

  // 4. OR que viraram PD (verificando nos itens)
  if (especie === "OR" && Array.isArray(pedido.itens)) {
    const temConversaoPD = pedido.itens.some(
      item => item.especieFaturamento === "PD" && item.numeroFaturamento
    );

    if (temConversaoPD) {
      const itemPD = pedido.itens.find(item => item.especieFaturamento === "PD");
      OR_convertidos_para_PD.push({
        numeroOR: numero,
        numeroPD: itemPD?.numeroFaturamento,
        vendedor,
        cliente,
        valor
      });
    }
  }
}

// Calcula totais
const totalOR = OR_naoFaturados.length + OR_convertidos_para_PD.length;
const convertidos = OR_convertidos_para_PD.length;
const faturados = PD_faturados.length;

// Retorna no formato do n8n
return [
  {
    json: {
      resumo: {
        OR_naoFaturados_qtd: OR_naoFaturados.length,
        OR_naoFaturados_valor: OR_naoFaturados.reduce((sum, p) => sum + p.valor, 0),

        PD_total_qtd: PD_total.length,
        PD_total_valor: PD_total.reduce((sum, p) => sum + p.valor, 0),

        PD_faturados_qtd: PD_faturados.length,
        PD_faturados_valor: PD_faturados.reduce((sum, p) => sum + p.valor, 0),

        OR_convertidos_para_PD_qtd: OR_convertidos_para_PD.length,
        OR_convertidos_para_PD_valor: OR_convertidos_para_PD.reduce((sum, p) => sum + p.valor, 0)
      },
      funil: {
        total_orcamentos_OR: totalOR,
        OR_convertidos_para_PD: convertidos,
        percentual_conversao: totalOR > 0 ? ((convertidos / totalOR) * 100).toFixed(1) + "%" : "0%",
        PD_ja_faturados: faturados,
        percentual_faturamento: convertidos > 0 ? ((faturados / convertidos) * 100).toFixed(1) + "%" : "0%"
      },
      detalhes: {
        OR_naoFaturados,
        PD_total,
        PD_faturados,
        OR_convertidos_para_PD
      }
    }
  }
];
